import React, { useState } from 'react';
import styles from './ShopPreview.module.css';

const SHOPS = [
  {
    id: 0,
    name: 'TechNova Store',
    niche: 'High-Tech',
    emoji: '🖥️',
    accent: '#3b82f6',
    gradient: 'linear-gradient(135deg, #0d1b2a 0%, #1b3a5c 100%)',
    url: 'technova-store.myshopify.com',
    heroTitle: 'Les meilleurs gadgets tech',
    heroSub: 'Livraison rapide · Qualité premium',
    products: [
      { name: 'Montre connectée Pro X', price: '49,99€', old: '99,99€' },
      { name: 'Écouteurs sans fil V2',  price: '34,99€', old: '79,99€' },
      { name: 'Chargeur rapide 100W',   price: '24,99€', old: '49,99€' },
      { name: 'Support téléphone auto', price: '19,99€', old: '39,99€' },
    ],
  },
  {
    id: 1,
    name: 'GlowUp Beauty',
    niche: 'Beauté',
